import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { HackathonService } from '../../../../core/services/hackathon.service';
import { SottomissioneService } from '../../../../core/services/sottomissione.service';
import { HackathonSummaryDTO } from '../../../../core/models/hackathon.model';

@Component({
  selector: 'app-judge-hackathon-dashboard',
  templateUrl: './judge-hackathon-dashboard.component.html',
  styleUrls: ['./judge-hackathon-dashboard.component.scss']
})
export class JudgeHackathonDashboardComponent implements OnInit {
  hackathonId: string | null = null;
  hackathon: HackathonSummaryDTO | null = null;
  activeTab: 'submissions' | 'ranking' = 'submissions';
  submissions: any[] = [];
  ranking: any[] = [];
  isLoading = true;
  errorMessage = '';
  isClosing = false;
  showEvaluationModal = false;
  selectedSubmission: any = null;
  evaluationForm = {
    voto: 0,
    giudizio: ''
  };

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private hackathonService: HackathonService,
    private sottomissioneService: SottomissioneService
  ) {}

  ngOnInit(): void {
    this.route.paramMap.subscribe(params => {
      this.hackathonId = params.get('id');
      if (this.hackathonId) {
        this.loadData();
      }
    });
  }

  loadData(): void {
    if (!this.hackathonId) return;
    this.isLoading = true;

    // In a real app we would use forkJoin, but for simplicity:
    this.hackathonService.getHackathonById(this.hackathonId).subscribe({
      next: (data) => {
        this.hackathon = data;
        this.loadSubmissions();
        this.loadRanking();
      },
      error: (err) => {
        this.errorMessage = 'Errore nel caricamento dell\'hackathon.';
        this.isLoading = false;
      }
    });
  }

  loadSubmissions(): void {
    if (!this.hackathonId) return;
    this.sottomissioneService.getSubmissionsByHackathon(this.hackathonId).subscribe({
      next: (data) => {
        this.submissions = data;
        this.isLoading = false;
      },
      error: (err) => {
        console.error('Error loading submissions', err);
        this.isLoading = false;
      }
    });
  }

  loadRanking(): void {
    if (!this.hackathonId) return;
    this.hackathonService.getClassifica(this.hackathonId).subscribe({
      next: (data: any[]) => this.ranking = data,
      error: (err: any) => console.error('Error loading ranking', err)
    });
  }

  switchTab(tab: 'submissions' | 'ranking'): void {
    this.activeTab = tab;
  }

  openEvaluationModal(submission: any): void {
    this.selectedSubmission = submission;
    this.evaluationForm = {
      voto: submission.valutazione?.voto || 0,
      giudizio: submission.valutazione?.giudizio || ''
    };
    this.showEvaluationModal = true;
  }

  closeEvaluationModal(): void {
    this.showEvaluationModal = false;
    this.selectedSubmission = null;
  }

  submitEvaluation(): void {
    if (!this.selectedSubmission) return;

    if (this.evaluationForm.voto < 0 || this.evaluationForm.voto > 10) {
      alert('Voto non valido. Inserisci un numero tra 0 e 10.');
      return;
    }

    const request = {
      idSottomissione: this.selectedSubmission.id,
      voto: this.evaluationForm.voto,
      giudizio: this.evaluationForm.giudizio
    };

    this.sottomissioneService.valutaSottomissione(this.selectedSubmission.id, request).subscribe({
      next: () => {
        alert('Valutazione salvata con successo!');
        this.closeEvaluationModal();
        this.loadSubmissions();
        this.loadRanking();
      },
      error: (err) => alert('Errore durante il salvataggio: ' + (err.error?.message || err.message))
    });
  }

  closeEvaluation(): void {
    if (!this.hackathonId || !confirm('Sei sicuro di voler chiudere la fase di valutazione? Non potrai più modificare i voti.')) return;

    this.isClosing = true;
    this.hackathonService.terminaFaseValutazione(this.hackathonId).subscribe({
      next: () => {
        this.loadData();
        this.isClosing = false;
      },
      error: (err) => {
        alert('Errore nella chiusura della valutazione: ' + err.error);
        this.isClosing = false;
      }
    });
  }
}
<div class="dashboard-container" *ngIf="!isLoading; else loading">
  <header class="dashboard-header" *ngIf="hackathon">
    <div class="header-content">
      <div class="status-chip">{{ hackathon.stato }}</div>
      <h1 class="hackathon-title">👨‍⚖️ Giudizio: {{ hackathon.nome }}</h1>
      <p class="hackathon-sub">{{ hackathon.luogo }} · {{ hackathon.premioInDenaro | currency:'EUR' }}</p>
    </div>

    <div class="header-actions" *ngIf="hackathon.stato === 'IN_VALUTAZIONE'">
      <button class="btn-primary" (click)="closeEvaluation()" [disabled]="isClosing">
        <span *ngIf="!isClosing">🏁 Chiudi Valutazione</span>
        <span *ngIf="isClosing">Chiusura in corso...</span>
      </button>
    </div>
  </header>

  <div class="tabs">
    <button class="tab" [class.active]="activeTab === 'submissions'" (click)="activeTab = 'submissions'">
      📦 Progetti ({{ submissions.length }})
    </button>
    <button class="tab" [class.active]="activeTab === 'ranking'" (click)="activeTab = 'ranking'">
      📊 Classifica
    </button>
  </div>

  <div class="tab-content">
    <!-- Submissions Tab -->
    <div *ngIf="activeTab === 'submissions'">
      <div class="card-grid" *ngIf="submissions.length > 0; else noSubmissions">
        <div class="submission-card" *ngFor="let s of submissions">
          <div class="card-header">
            <h3>{{ s.team.nomeTeam }}</h3>
          </div>
          <p class="desc">{{ s.descrizione }}</p>
          <div class="links">
            <a [href]="s.linkProgetto" target="_blank" class="github-link">🔗 Repository GitHub</a>
          </div>
          <div class="actions">
            <button class="btn-eval" (click)="openEvaluationModal(s)">
              {{ s.valutata ? '✅ Modifica Voto' : '📝 Valuta Roma' }}
            </button>
          </div>
        </div>
      </div>
      <ng-template #noSubmissions>
        <div class="empty-state">Nessun progetto sottomesso per questo hackathon.</div>
      </ng-template>
    </div>

    <!-- Ranking Tab -->
    <div *ngIf="activeTab === 'ranking'">
      <div class="ranking-list" *ngIf="ranking.length > 0; else noRanking">
        <div class="ranking-item" *ngFor="let r of ranking; let i = index">
          <span class="rank">{{ i + 1 }}°</span>
          <span class="team-name">{{ r.nomeTeam }}</span>
          <span class="points">{{ r.punteggio }} pt</span>
        </div>
      </div>
      <ng-template #noRanking>
        <div class="empty-state">La classifica sarà visibile dopo le prime valutazioni.</div>
      </ng-template>
    </div>
  </div>

  <!-- Evaluation Modal -->
  <div class="modal-overlay" *ngIf="showEvaluationModal">
    <div class="modal-content">
      <div class="modal-header">
        <h2>⭐ Valuta Progetto: {{ selectedSubmission?.team?.nomeTeam }}</h2>
        <button class="close-btn" (click)="closeEvaluationModal()">×</button>
      </div>

      <div class="modal-body">
        <div class="form-group">
          <label for="voto">Voto (0-10)</label>
          <input 
            type="number" 
            id="voto" 
            [(ngModel)]="evaluationForm.voto" 
            min="0" 
            max="10" 
            class="form-control">
        </div>

        <div class="form-group">
          <label for="giudizio">Giudizio</label>
          <textarea 
            id="giudizio" 
            [(ngModel)]="evaluationForm.giudizio" 
            rows="5" 
            class="form-control"
            placeholder="Inserisci un commento sulla sottomissione..."></textarea>
        </div>
      </div>

      <div class="modal-footer">
        <button class="btn-secondary" (click)="closeEvaluationModal()">Annulla</button>
        <button class="btn-primary" (click)="submitEvaluation()">Salva Valutazione</button>
      </div>
    </div>
  </div>
</div>

<ng-template #loading>
  <div class="loading-state">
    <div class="spinner"></div>
    <p>Caricamento dashboard...</p>
  </div>
</ng-template>
